import React from "react";
import style from "./Logo.module.css";

const Logo = () => {
  return (
    <div className={style.container}>
      <svg id="Слой_1" data-name="Слой 1" viewBox="0 0 174.43 174.43">
        <rect
          class="cls-1"
          x="5.5"
          y="5.5"
          width="163.43"
          height="163.43"
          rx="10.31"
        />
        <rect class="cls-2" x="78.82" y="60.24" width="16.79" height="90.65" />
        <circle class="cls-2" cx="87.21" cy="38.53" r="14.99" />
      </svg>
    </div>
  );
};

export default Logo;
